import requests
import json
from flask import Flask, request
app = Flask(__name__)


@app.route('/webhook', methods=['POST'])
def webhook():
    # Get the JSON payload from the request body
    data = request.get_json()

    # Print out the payload to the console for debugging purposes
    print(data)

    # Return a 200 response code back to the API Gateway
    return 'OK', 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')